import './Home.css'

function Home() {

	const [gameName, setGameName] = useState({
        name: ''
    });

	const handleGameName = (e) => {
		const { name, value } = e.target;
        setLoginData({
            ...gameName,
            [name]: value,
        });
	};

	return (
		<>
		<div className="title">
			RED-TETRIS
		</div>
		<div className="create-game">
			<input className="game-name" maxLength="10" placeholder="Entrer a name for create the game room" value={gameName.name} onChange={handleGameName}/>
			<button className='create-game-btn'> Creer </button>
		</div>
		</>
	);
}

export default Home;
